import android.view.MotionEvent
import android.widget.Spinner
import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.testutils.JvmTest
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.`is`
import org.junit.Test
import org.junit.runner.RunWith
import org.mockito.kotlin.mock

/**
 * Test to verify that the DeckSpinnerSelection touch listener correctly handles motion events.
 * This ensures that deck selection works properly in the note editor and add screen.
 *
 * Regression test for: https://github.com/ankidroid/Anki-Android/issues/14171
 */
@RunWith(AndroidJUnit4::class)
class DeckSpinnerSelectionTouchListenerTest : JvmTest() {

    @Test
    fun `touch listener returns false for ACTION_DOWN`() {
        val deckSpinnerSelection = createDeckSpinnerSelection()
        val spinner = deckSpinnerSelection.spinner

        // Get the touch listener that was set
        val listener = getSpinnerTouchListener(spinner)

        // Create a mock ACTION_DOWN event
        val downEvent = createMotionEvent(MotionEvent.ACTION_DOWN)

        // The listener should return false for ACTION_DOWN to allow normal touch processing
        val result = listener.onTouch(spinner, downEvent)
        assertThat("Touch listener should return false for ACTION_DOWN", result, `is`(false))
    }

    @Test
    fun `touch listener returns false for ACTION_MOVE`() {
        val deckSpinnerSelection = createDeckSpinnerSelection()
        val spinner = deckSpinnerSelection.spinner

        val listener = getSpinnerTouchListener(spinner)
        val moveEvent = createMotionEvent(MotionEvent.ACTION_MOVE)

        // The listener should return false for ACTION_MOVE to allow normal touch processing
        val result = listener.onTouch(spinner, moveEvent)
        assertThat("Touch listener should return false for ACTION_MOVE", result, `is`(false))
    }

    @Test
    fun `touch listener returns true for ACTION_UP`() {
        val deckSpinnerSelection = createDeckSpinnerSelection()
        val spinner = deckSpinnerSelection.spinner

        val listener = getSpinnerTouchListener(spinner)
        val upEvent = createMotionEvent(MotionEvent.ACTION_UP)

        // The listener should return true for ACTION_UP since it handles this event
        // by showing the deck selection dialog
        val result = listener.onTouch(spinner, upEvent)
        assertThat("Touch listener should return true for ACTION_UP", result, `is`(true))
    }

    private fun createDeckSpinnerSelection(): TestDeckSpinnerSelection {
        val activity = mock<AnkiActivity>()
        val collection = col
        val spinner = Spinner(targetContext)

        return TestDeckSpinnerSelection(
            activity,
            collection,
            spinner,
            showAllDecks = false,
            alwaysShowDefault = false,
            showFilteredDecks = false
        )
    }

    private fun getSpinnerTouchListener(spinner: Spinner): android.view.View.OnTouchListener {
        // Use reflection to get the touch listener that was set
        val field = android.view.View::class.java.getDeclaredField("mListenerInfo")
        field.isAccessible = true
        val listenerInfo = field.get(spinner)

        if (listenerInfo != null) {
            val touchListenerField = listenerInfo.javaClass.getDeclaredField("mOnTouchListener")
            touchListenerField.isAccessible = true
            return touchListenerField.get(listenerInfo) as android.view.View.OnTouchListener
        }

        throw IllegalStateException("No touch listener set on spinner")
    }

    private fun createMotionEvent(action: Int): MotionEvent {
        val downTime = System.currentTimeMillis()
        val eventTime = System.currentTimeMillis()
        val x = 0f
        val y = 0f
        val metaState = 0
        return MotionEvent.obtain(downTime, eventTime, action, x, y, metaState)
    }

    /**
     * Test subclass that exposes the spinner and overrides displayDeckSelectionDialog
     * to avoid showing actual dialogs during tests
     */
    private class TestDeckSpinnerSelection(
        context: AnkiActivity,
        collection: com.ichi2.libanki.Collection,
        val spinner: Spinner,
        showAllDecks: Boolean,
        alwaysShowDefault: Boolean,
        showFilteredDecks: Boolean
    ) : DeckSpinnerSelection(
        context,
        collection,
        spinner,
        showAllDecks,
        alwaysShowDefault,
        showFilteredDecks
    ) {
        init {
            // Initialize the spinner with a listener
            setSpinnerListener()
        }

        override fun displayDeckSelectionDialog(col: com.ichi2.libanki.Collection?) {
            // Override to prevent showing actual dialog in tests
            // In real usage, this would show the DeckSelectionDialog
        }
    }
}
