            if (motionEvent.action == MotionEvent.ACTION_UP) {
                // Handle ACTION_UP by showing dialog (mocked here)
                true
            } else {
                false
            }
        }

        val downEvent = createMotionEvent(MotionEvent.ACTION_DOWN)
        val moveEvent = createMotionEvent(MotionEvent.ACTION_MOVE)
        val upEvent = createMotionEvent(MotionEvent.ACTION_UP)

        // Verify the behavior
        assertThat(
            "Touch listener should return false for ACTION_DOWN to allow normal processing",
            fixedListener.onTouch(null, downEvent),
            `is`(false)
        )

        assertThat(
            "Touch listener should return false for ACTION_MOVE to allow normal processing",
            fixedListener.onTouch(null, moveEvent),
            `is`(false)
        )

        assertThat(
            "Touch listener should return true for ACTION_UP to handle the event",
            fixedListener.onTouch(null, upEvent),
            `is`(true)
        )

        // Clean up events
        downEvent.recycle()
        moveEvent.recycle()
        upEvent.recycle()
    }

